SELECT * FROM tb_driver
WHERE tenant_id = #{tenantId}
  AND channel_id = #{channelId}

    AND (driver_name LIKE CONCAT('%', #{searchKeyword}, '%') OR license_no LIKE CONCAT('%', #{searchKeyword}, '%'))

ORDER BY created_at DESC
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(*) FROM tb_driver
WHERE tenant_id = #{tenantId}
  AND channel_id = #{channelId}

    AND (driver_name LIKE CONCAT('%', #{searchKeyword}, '%') OR license_no LIKE CONCAT('%', #{searchKeyword}, '%'))

SELECT * FROM tb_vehicle
WHERE tenant_id = #{tenantId}
  AND channel_id = #{channelId}

    AND plate_no LIKE CONCAT('%', #{searchKeyword}, '%')

ORDER BY created_at DESC
LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(*) FROM tb_vehicle
WHERE tenant_id = #{tenantId}
  AND channel_id = #{channelId}

    AND plate_no LIKE CONCAT('%', #{searchKeyword}, '%')
